119→	it, err := r.ItemService.UpdateSensitivity(ctx, claims.UserID, itemID, sensitivityToString(&sensitivity))
120→	if err != nil {
121→		return nil, fmt.Errorf("resolver: update sensitivity: %w", err)
122→	}
123→	return toGraphQLItem(it), nil
124→}
125→
126→// TagItem is the resolver for the tagItem field.
127→func (r *mutationResolver) TagItem(ctx context.Context, id string, tags []string) (*model.Item, error) {
128→	claims, err := requireAuth(ctx)
129→	if err != nil {
130→		return nil, err
131→	}
132→
133→	itemID, err := uuid.Parse(id)
134→	if err != nil {
135→		return nil, fmt.Errorf("resolver: invalid item id: %w", err)
136→	}
137→
138→	it, err := r.ItemService.Tag(ctx, claims.UserID, itemID, tags)
139→	if err != nil {
140→		return nil, fmt.Errorf("resolver: tag item: %w", err)
141→	}
142→	return toGraphQLItem(it), nil
143→}
144→
145→// Item is the resolver for the item field.
146→func (r *queryResolver) Item(ctx context.Context, id string) (*model.Item, error) {
147→	claims, err := requireAuth(ctx)
148→	if err != nil {
149→		return nil, err
150→	}
151→
152→	itemID, err := uuid.Parse(id)
153→	if err != nil {
154→		return nil, fmt.Errorf("resolver: invalid item id: %w", err)
155→	}
156→
157→	it, err := r.ItemService.GetByID(ctx, claims.UserID, itemID)
158→	if err != nil {
159→		return nil, fmt.Errorf("resolver: item: %w", err)
160→	}
161→	if it == nil {
162→		return nil, nil
163→	}
164→	return toGraphQLItem(it), nil
165→}
166→
167→// Items is the resolver for the items field.
168→func (r *queryResolver) Items(ctx context.Context, filter *model.ItemFilter, limit *int, offset *int, sort *model.ItemSort) (*model.SearchResult, error) {
169→	claims, err := requireAuth(ctx)
170→	if err != nil {
171→		return nil, err
172→	}
173→
174→	result, err := r.ItemService.List(ctx, claims.UserID,
175→		toItemFilter(filter),
176→		derefIntOr(limit, 20),
177→		derefIntOr(offset, 0),
178→		toItemSort(sort))
179→	if err != nil {
180→		return nil, fmt.Errorf("resolver: items: %w", err)
181→	}
182→
183→	return &model.SearchResult{
184→		Items:   toGraphQLItems(result.Items),
185→		Total:   result.Total,
186→		HasMore: result.HasMore,
187→	}, nil
188→}
189→
190→// Search is the resolver for the search field.
191→func (r *queryResolver) Search(ctx context.Context, query string, filter *model.ItemFilter, limit *int, threshold *float64) (*model.SearchResult, error) {
192→	claims, err := requireAuth(ctx)
193→	if err != nil {
194→		return nil, err
195→	}
196→
197→	result, err := r.ItemService.Search(ctx, claims.UserID, query,
198→		toItemFilter(filter),
199→		derefIntOr(limit, 20),
200→		derefFloat64Or(threshold, 0.0))
201→	if err != nil {
202→		return nil, fmt.Errorf("resolver: search: %w", err)
203→	}
204→
205→	return &model.SearchResult{
206→		Items:   toGraphQLItems(result.Items),
207→		Total:   result.Total,
208→		HasMore: result.HasMore,
209→	}, nil
210→}
211→
212→// Mutation returns generated.MutationResolver implementation.
213→func (r *Resolver) Mutation() generated.MutationResolver { return &mutationResolver{r} }
214→
215→// Query returns generated.QueryResolver implementation.
216→func (r *Resolver) Query() generated.QueryResolver { return &queryResolver{r} }
217→
218→type mutationResolver struct{ *Resolver }
219→type queryResolver struct{ *Resolver }
