 25→// toGraphQLItem maps a domain Item to the GraphQL model Item.
 26→func toGraphQLItem(it *item.Item) *model.Item {
 27→	return &model.Item{
 28→		ID:           it.ID.String(),
 29→		Type:         model.ItemType(strings.ToUpper(it.Type)),
 30→		Status:       model.ItemStatus(strings.ToUpper(it.Status)),
 31→		Sensitivity:  model.SensitivityLevel(strings.ToUpper(it.Sensitivity)),
 32→		Title:        it.Title,
 33→		ContentText:  it.ContentText,
 34→		ContentURL:   it.ContentURL,
 35→		Tags:         ensureStringSlice(it.Tags),
 36→		Metadata:     ensureMap(it.Metadata),
 37→		AutoMetadata: ensureMap(it.AutoMetadata),
 38→		Source:       it.Source,
 39→		SourceURL:    it.SourceURL,
 40→		CreatedAt:    it.CreatedAt,
 41→		UpdatedAt:    it.UpdatedAt,
 42→		CapturedAt:   it.CapturedAt,
 43→	}
 44→}
 45→
 46→// toGraphQLItems maps a slice of domain Items to GraphQL model Items.
 47→func toGraphQLItems(items []*item.Item) []*model.Item {
 48→	result := make([]*model.Item, len(items))
 49→	for i, it := range items {
 50→		result[i] = toGraphQLItem(it)
 51→	}
 52→	return result
 53→}
 54→
 55→// toItemFilter converts a GraphQL ItemFilter to a domain Filter.
 56→func toItemFilter(f *model.ItemFilter) *item.Filter {
 57→	if f == nil {
 58→		return nil
 59→	}
 60→	result := &item.Filter{
 61→		Source: f.Source,
 62→	}
 63→	for _, t := range f.Types {
 64→		result.Types = append(result.Types, strings.ToLower(string(t)))
 65→	}
 66→	for _, s := range f.Status {
 67→		result.Status = append(result.Status, strings.ToLower(string(s)))
 68→	}
 69→	for _, s := range f.Sensitivity {
 70→		result.Sensitivity = append(result.Sensitivity, strings.ToLower(string(s)))
 71→	}
 72→	result.Tags = f.Tags
 73→	if f.DateFrom != nil {
 74→		result.DateFrom = f.DateFrom
 75→	}
 76→	if f.DateTo != nil {
 77→		result.DateTo = f.DateTo
 78→	}
 79→	return result
 80→}
 81→
 82→// toItemSort converts a GraphQL ItemSort to a domain Sort.
 83→func toItemSort(s *model.ItemSort) *item.Sort {
 84→	if s == nil {
 85→		return nil
 86→	}
 87→	return &item.Sort{
 88→		Field:     string(s.Field),
 89→		Direction: string(s.Direction),
 90→	}
 91→}
 92→
 93→// sensitivityToString converts a GraphQL SensitivityLevel to lowercase DB string.
 94→// Returns "normal" if nil.
 95→func sensitivityToString(s *model.SensitivityLevel) string {
 96→	if s == nil {
 97→		return "normal"
 98→	}
 99→	return strings.ToLower(string(*s))
100→}
101→
102→func ensureStringSlice(s []string) []string {
103→	if s == nil {
104→		return []string{}
105→	}
106→	return s
107→}
108→
109→func ensureMap(m map[string]any) map[string]any {
110→	if m == nil {
111→		return map[string]any{}
112→	}
113→	return m
114→}
115→
116→func derefIntOr(p *int, def int) int {
117→	if p == nil {
118→		return def
119→	}
120→	return *p
121→}
122→
123→func derefFloat64Or(p *float64, def float64) float64 {
124→	if p == nil {
125→		return def
126→	}
127→	return *p
128→}
129→
130→// toGraphQLUser maps a domain User to the GraphQL model User.
131→func toGraphQLUser(u *user.User) *model.User {
132→	return &model.User{
133→		ID:          u.ID.String(),
134→		Email:       u.Email,
135→		DisplayName: u.DisplayName,
136→		CreatedAt:   u.CreatedAt,
137→		UpdatedAt:   u.UpdatedAt,
138→	}
139→}
