package item

import (
	"context"
	"errors"
	"fmt"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
)

const maxLimit = 100

// itemColumns is the canonical SELECT column list for the items table.
const itemColumns = `id, owner_id, type, status, sensitivity, title, content_text,
	content_url, tags, metadata, auto_metadata, source, source_url,
	created_at, updated_at, captured_at`

// Service provides item CRUD and search operations.
type Service struct {
	pool *pgxpool.Pool
}

// New creates a new item Service.
func New(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// GetByID returns a single item by ID and owner. Returns nil, nil if not found.
func (s *Service) GetByID(ctx context.Context, ownerID, itemID uuid.UUID) (*Item, error) {
	query := fmt.Sprintf(`SELECT %s FROM items WHERE owner_id = $1 AND id = $2`, itemColumns)
	row := s.pool.QueryRow(ctx, query, ownerID, itemID)
	it, err := scanItem(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("item: get by id: %w", err)
	}
	return it, nil
}

// List returns a page of items matching the given filter, sorted and paginated.
func (s *Service) List(ctx context.Context, ownerID uuid.UUID, filter *Filter, limit, offset int, sort *Sort) (*SearchResult, error) {
	limit = clampLimit(limit, maxLimit)
	offset = clampOffset(offset)

	qb := &queryBuilder{}
	qb.add("owner_id = $%d", ownerID)
	applyFilter(qb, filter)
	whereClause := qb.where()

	// Count total
	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
	var total int
	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
		return nil, fmt.Errorf("item: list count: %w", err)
	}

	// Determine sort
	orderCol := "created_at"
	orderDir := "DESC"
	if sort != nil {
		if col, ok := sortFieldToColumn(sort.Field); ok {
			orderCol = col
		}
		orderDir = sortDirectionSQL(sort.Direction)
	}

	dataQuery := fmt.Sprintf(`SELECT %s FROM items %s ORDER BY %s %s LIMIT $%d OFFSET $%d`,
		itemColumns, whereClause, orderCol, orderDir, qb.nextParam(), qb.nextParam()+1)
	qb.args = append(qb.args, limit, offset)

	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
	if err != nil {
		return nil, fmt.Errorf("item: list query: %w", err)
	}
	defer rows.Close()

	items, err := scanItems(rows)
	if err != nil {
		return nil, fmt.Errorf("item: list scan: %w", err)
	}

	return &SearchResult{
		Items:   items,
		Total:   total,
		HasMore: offset+len(items) < total,
	}, nil
}

// Search performs full-text search over items using the search_vector column.
func (s *Service) Search(ctx context.Context, ownerID uuid.UUID, query string, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
	if query == "" {
		return &SearchResult{Items: []*Item{}}, nil
	}
	limit = clampLimit(limit, maxLimit)

	qb := &queryBuilder{}
	qb.add("owner_id = $%d", ownerID)
	qb.add("search_vector @@ plainto_tsquery('english', $%d)", query)
	applyFilter(qb, filter)
	whereClause := qb.where()

	// Count total matches
	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
	var total int
	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
		return nil, fmt.Errorf("item: search count: %w", err)
	}

	dataQuery := fmt.Sprintf(
		`SELECT %s FROM items %s ORDER BY ts_rank(search_vector, plainto_tsquery('english', $2)) DESC LIMIT $%d`,
		itemColumns, whereClause, qb.nextParam())
	qb.args = append(qb.args, limit)

	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
	if err != nil {
		return nil, fmt.Errorf("item: search query: %w", err)
	}
	defer rows.Close()

	items, err := scanItems(rows)
	if err != nil {
		return nil, fmt.Errorf("item: search scan: %w", err)
	}

	return &SearchResult{
		Items:   items,
		Total:   total,
		HasMore: len(items) < total,
	}, nil
}

// CaptureBookmark creates a new bookmark item.
func (s *Service) CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input BookmarkInput) (*Item, error) {
	if input.URL == "" {
		return nil, fmt.Errorf("item: capture bookmark: url is required")
	}
	if input.Source == "" {
		input.Source = "api"
	}
	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}

	tags := input.Tags
	if tags == nil {
		tags = []string{}
	}

	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_url, tags, source, metadata, auto_metadata)
		VALUES ($1, 'bookmark', 'pending', $2, $3, $4, $5, $6, '{}', '{}')
		RETURNING %s`, itemColumns)

	row := s.pool.QueryRow(ctx, query,
		ownerID, input.Sensitivity, input.Title, input.URL, tags, input.Source)

	it, err := scanItem(row)
	if err != nil {
		return nil, fmt.Errorf("item: capture bookmark: %w", err)
	}
	return it, nil
}

// CaptureNote creates a new text note item.
func (s *Service) CaptureNote(ctx context.Context, ownerID uuid.UUID, input NoteInput) (*Item, error) {
	if input.Content == "" {
		return nil, fmt.Errorf("item: capture note: content is required")
	}
	if input.Source == "" {
		input.Source = "api"
	}
	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}

	tags := input.Tags
	if tags == nil {
		tags = []string{}
	}

	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_text, tags, source, metadata, auto_metadata)
		VALUES ($1, 'text_note', 'ready', $2, $3, $4, $5, $6, '{}', '{}')
		RETURNING %s`, itemColumns)

	row := s.pool.QueryRow(ctx, query,
		ownerID, input.Sensitivity, input.Title, input.Content, tags, input.Source)

	it, err := scanItem(row)
	if err != nil {
		return nil, fmt.Errorf("item: capture note: %w", err)
	}
	return it, nil
}

// Update partially updates an item. Only non-nil fields in input are changed.
func (s *Service) Update(ctx context.Context, ownerID, itemID uuid.UUID, input UpdateInput) (*Item, error) {
	sets := []string{}
	args := []any{ownerID, itemID}
	paramIdx := 3

	if input.Title != nil {
		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
		args = append(args, *input.Title)
		paramIdx++
	}
	if input.Tags != nil {
		sets = append(sets, fmt.Sprintf("tags = $%d", paramIdx))
		args = append(args, input.Tags)
		paramIdx++
	}
	if input.Sensitivity != nil {
		sets = append(sets, fmt.Sprintf("sensitivity = $%d", paramIdx))
		args = append(args, *input.Sensitivity)
		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
	}

	if len(sets) == 0 {
		return s.GetByID(ctx, ownerID, itemID)
	}

	query := fmt.Sprintf(`UPDATE items SET %s WHERE owner_id = $1 AND id = $2 RETURNING %s`,
		joinSets(sets), itemColumns)

	row := s.pool.QueryRow(ctx, query, args...)
	it, err := scanItem(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, fmt.Errorf("item: update: not found")
	}
	if err != nil {
		return nil, fmt.Errorf("item: update: %w", err)
	}
	return it, nil
}

// Delete removes an item by ID and owner. Returns an error if not found.
func (s *Service) Delete(ctx context.Context, ownerID, itemID uuid.UUID) error {
	tag, err := s.pool.Exec(ctx,
		"DELETE FROM items WHERE owner_id = $1 AND id = $2",
		ownerID, itemID)
	if err != nil {
		return fmt.Errorf("item: delete: %w", err)
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("item: delete: not found")
	}
	return nil
}

// UpdateSensitivity changes an item's sensitivity level.
func (s *Service) UpdateSensitivity(ctx context.Context, ownerID, itemID uuid.UUID, sensitivity string) (*Item, error) {
	query := fmt.Sprintf(`UPDATE items SET sensitivity = $3 WHERE owner_id = $1 AND id = $2 RETURNING %s`, itemColumns)
	row := s.pool.QueryRow(ctx, query, ownerID, itemID, sensitivity)
	it, err := scanItem(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, fmt.Errorf("item: update sensitivity: not found")
	}
	if err != nil {
		return nil, fmt.Errorf("item: update sensitivity: %w", err)
	}
	return it, nil
}

// Tag replaces an item's tags.
func (s *Service) Tag(ctx context.Context, ownerID, itemID uuid.UUID, tags []string) (*Item, error) {
	if tags == nil {
		tags = []string{}
	}
	query := fmt.Sprintf(`UPDATE items SET tags = $3 WHERE owner_id = $1 AND id = $2 RETURNING %s`, itemColumns)
	row := s.pool.QueryRow(ctx, query, ownerID, itemID, tags)
	it, err := scanItem(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, fmt.Errorf("item: tag: not found")
	}
	if err != nil {
		return nil, fmt.Errorf("item: tag: %w", err)
	}
	return it, nil
}

func joinSets(sets []string) string {
	result := ""
	for i, s := range sets {
		if i > 0 {
			result += ", "
		}
		result += s
	}
	return result
}

package main

import (
	"context"
	"flag"
	"log/slog"
	"os"
	"os/signal"
	"syscall"

	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/joho/godotenv"
	"github.com/riverqueue/river"
	"github.com/riverqueue/river/riverdriver/riverpgxv5"

	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/db"
	"github.com/ketang/flotsam/api/internal/version"
	"github.com/ketang/flotsam/api/internal/worker"
)

func main() {
	watch := flag.Bool("watch", false, "run continuously, polling for jobs until interrupted")
	once := flag.Bool("once", false, "process pending jobs and exit")
	flag.Parse()

	// Default to --once if neither flag is specified
	if !*watch && !*once {
		*once = true
	}

	// 1. Load .env (no-op if file is absent)
	_ = godotenv.Load()

	// 2. Parse and validate configuration
	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// 3. Configure structured logger
	slog.SetDefault(slog.New(cfg.LogHandler()))
	slog.Info("starting flotsam-worker",
		"version", version.Version,
		"mode", workerMode(*watch),
	)

	// 4. Connect to database
	ctx := context.Background()
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1)
	}
	defer pool.Close()

	// 5. Create River client with workers registered
	riverClient, err := newRiverClient(pool)
	if err != nil {
		slog.Error("failed to create river client", "error", err)
		os.Exit(1)
	}

	// 6. Start the River client
	if err := riverClient.Start(ctx); err != nil {
		slog.Error("failed to start river client", "error", err)
		os.Exit(1)
	}
	slog.Info("worker: river client started")

	if *watch {
		// Block on SIGINT/SIGTERM, then graceful shutdown
		sigCh := make(chan os.Signal, 1)
		signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
		sig := <-sigCh
		slog.Info("signal received, shutting down", "signal", sig)
	} else {
		// --once: wait briefly for any pending jobs, then stop
		slog.Info("worker: processing pending jobs")
	}

	shutdownCtx, cancel := context.WithTimeout(context.Background(), cfg.ShutdownTimeout)
	defer cancel()

	if err := riverClient.Stop(shutdownCtx); err != nil {
		slog.Error("worker: shutdown error", "error", err)
		os.Exit(1)
	}
	slog.Info("worker: shutdown complete")
}

func newRiverClient(pool *pgxpool.Pool) (*river.Client[pgx.Tx], error) {
	return river.NewClient(riverpgxv5.New(pool), &river.Config{
		Workers: worker.Workers(),
		Queues: map[string]river.QueueConfig{
			river.QueueDefault: {MaxWorkers: 100},
		},
	})
}

func workerMode(watch bool) string {
	if watch {
		return "watch"
	}
	return "once"
}

package router

import (
	"encoding/json"
	"log/slog"
	"net/http"
	"strings"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/99designs/gqlgen/graphql/playground"
	"github.com/go-chi/chi/v5"
	chimiddleware "github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/cors"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/graph/generated"
	"github.com/ketang/flotsam/api/graph/resolver"
	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/item"
	flotsammiddleware "github.com/ketang/flotsam/api/internal/middleware"
	"github.com/ketang/flotsam/api/internal/storage"
	"github.com/ketang/flotsam/api/internal/user"
	"github.com/ketang/flotsam/api/internal/version"
)

// Deps holds the dependencies needed to construct the router.
type Deps struct {
	Config      *config.Config
	Pool        *pgxpool.Pool
	Validator   auth.Validator
	Storage     *storage.Client // nil if S3 not configured
	RiverClient *river.Client[pgx.Tx]
	Items       *item.Service
	Users       *user.Service
	Issuer      *auth.Issuer
}

// New constructs the chi router with all middleware, routes, and handlers.
func New(deps Deps) http.Handler {
	r := chi.NewRouter()

	// Global middleware (applied to every request)
	r.Use(flotsammiddleware.RequestID)
	r.Use(flotsammiddleware.Logging)
	r.Use(flotsammiddleware.Recovery)
	r.Use(chimiddleware.RealIP)
	r.Use(chimiddleware.StripSlashes)

	// CORS (if configured)
	if deps.Config.CORSOrigins != "" {
		origins := parseCORSOrigins(deps.Config.CORSOrigins)
		r.Use(cors.Handler(cors.Options{
			AllowedOrigins:   origins,
			AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE", "OPTIONS"},
			AllowedHeaders:   []string{"Accept", "Authorization", "Content-Type"},
			AllowCredentials: true,
			MaxAge:           300,
		}))
	}

	// Health endpoint — no auth
	r.Get("/health", healthHandler)

	// GraphQL handler
	gqlSrv := handler.New(generated.NewExecutableSchema(generated.Config{
		Resolvers: &resolver.Resolver{
			ItemService: deps.Items,
			UserService: deps.Users,
			Issuer:      deps.Issuer,
		},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	if deps.Config.GQLIntrospection {
		gqlSrv.Use(extension.Introspection{})
	}

	// GraphQL endpoint — optional auth + rate limit
	r.Route("/graphql", func(r chi.Router) {
		r.Use(flotsammiddleware.OptionalAuth(deps.Validator))
		if deps.Config.RateLimitEnabled {
			rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitGraphQL)
			r.Use(rl.Limit)
		}
		r.Post("/", gqlSrv.ServeHTTP)
		r.Get("/", gqlSrv.ServeHTTP)
	})

	// GraphQL playground (dev only)
	if deps.Config.GQLPlayground {
		r.Get("/playground", playground.Handler("Flotsam API", "/graphql"))
		slog.Info("router: GraphQL playground enabled at /playground")
	}

	// MCP endpoint — mandatory auth + rate limit
	if deps.Config.MCPEnabled {
		r.Route("/mcp", func(r chi.Router) {
			r.Use(flotsammiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitMCP)
				r.Use(rl.Limit)
			}
			r.Handle("/*", placeholderHandler("mcp"))
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// Upload endpoint — mandatory auth
	r.Route("/upload", func(r chi.Router) {
		r.Use(flotsammiddleware.Auth(deps.Validator))
		r.Post("/", placeholderHandler("upload"))
	})

	slog.Info("router: initialized",
		"cors_origins", deps.Config.CORSOrigins,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
	)

	return r
}

func healthHandler(w http.ResponseWriter, _ *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(map[string]string{
		"status":  "ok",
		"version": version.Version,
	})
}

func placeholderHandler(name string) http.HandlerFunc {
	return func(w http.ResponseWriter, _ *http.Request) {
		http.Error(w, name+" endpoint not yet implemented", http.StatusNotImplemented)
	}
}

func parseCORSOrigins(s string) []string {
	parts := strings.Split(s, ",")
	origins := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			origins = append(origins, p)
		}
	}
	return origins
}

