package provider

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"mime/multipart"
	"net/http"
)

const defaultWhisperModel = "whisper-1"
const defaultWhisperBaseURL = "https://api.openai.com/v1"

// WhisperAPIProvider transcribes audio via the OpenAI Whisper API.
type WhisperAPIProvider struct {
	apiKey  string
	model   string
	baseURL string
	client  *http.Client
}

// NewWhisperAPI creates a WhisperAPIProvider using the given API key.
func NewWhisperAPI(apiKey string, opts ...WhisperAPIOption) *WhisperAPIProvider {
	p := &WhisperAPIProvider{
		apiKey:  apiKey,
		model:   defaultWhisperModel,
		baseURL: defaultWhisperBaseURL,
		client:  http.DefaultClient,
	}
	for _, o := range opts {
		o(p)
	}
	return p
}

// WhisperAPIOption configures a WhisperAPIProvider.
type WhisperAPIOption func(*WhisperAPIProvider)

// WithModel sets the Whisper model name.
func WithModel(model string) WhisperAPIOption {
	return func(p *WhisperAPIProvider) { p.model = model }
}

// WithBaseURL overrides the API base URL (useful for testing).
func WithBaseURL(url string) WhisperAPIOption {
	return func(p *WhisperAPIProvider) { p.baseURL = url }
}

// WithHTTPClient sets a custom HTTP client.
func WithHTTPClient(c *http.Client) WhisperAPIOption {
	return func(p *WhisperAPIProvider) { p.client = c }
}

// whisperResponse is the JSON response from the OpenAI transcription endpoint.
type whisperResponse struct {
	Text string `json:"text"`
}

// Transcribe sends audio to the OpenAI Whisper API and returns the transcript.
func (p *WhisperAPIProvider) Transcribe(ctx context.Context, audio io.Reader, opts TranscribeOpts) (string, error) {
	var buf bytes.Buffer
	w := multipart.NewWriter(&buf)

	// model field
	if err := w.WriteField("model", p.model); err != nil {
		return "", fmt.Errorf("provider: whisper api: write model field: %w", err)
	}

	// optional language
	if opts.Language != "" {
		if err := w.WriteField("language", opts.Language); err != nil {
			return "", fmt.Errorf("provider: whisper api: write language field: %w", err)
		}
	}

	// audio file part
	filename := "audio"
	if opts.Format != "" {
		filename = "audio." + opts.Format
	}
	part, err := w.CreateFormFile("file", filename)
	if err != nil {
		return "", fmt.Errorf("provider: whisper api: create form file: %w", err)
	}
	if _, err := io.Copy(part, audio); err != nil {
		return "", fmt.Errorf("provider: whisper api: copy audio: %w", err)
	}
	if err := w.Close(); err != nil {
		return "", fmt.Errorf("provider: whisper api: close multipart: %w", err)
	}

	url := p.baseURL + "/audio/transcriptions"
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, url, &buf)
	if err != nil {
		return "", fmt.Errorf("provider: whisper api: create request: %w", err)
	}
	req.Header.Set("Authorization", "Bearer "+p.apiKey)
	req.Header.Set("Content-Type", w.FormDataContentType())

	resp, err := p.client.Do(req)
	if err != nil {
		return "", fmt.Errorf("provider: whisper api: request: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(io.LimitReader(resp.Body, 1024))
		return "", fmt.Errorf("provider: whisper api: status %d: %s", resp.StatusCode, string(body))
	}

	var result whisperResponse
	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
		return "", fmt.Errorf("provider: whisper api: decode response: %w", err)
	}

	if result.Text == "" {
		return "", fmt.Errorf("provider: whisper api: empty transcript")
	}

	return result.Text, nil
}

