package provider

import (
	"bytes"
	"context"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// WhisperLocalProvider transcribes audio using a local whisper.cpp binary.
type WhisperLocalProvider struct {
	binaryPath string
	modelPath  string
}

// NewWhisperLocal creates a WhisperLocalProvider.
func NewWhisperLocal(binaryPath, modelPath string) *WhisperLocalProvider {
	return &WhisperLocalProvider{
		binaryPath: binaryPath,
		modelPath:  modelPath,
	}
}

// Transcribe writes audio to a temp file, runs whisper.cpp, and returns the transcript.
func (p *WhisperLocalProvider) Transcribe(ctx context.Context, audio io.Reader, opts TranscribeOpts) (string, error) {
	ext := "wav"
	if opts.Format != "" {
		ext = opts.Format
	}

	tmpFile, err := os.CreateTemp("", "whisper-*."+ext)
	if err != nil {
		return "", fmt.Errorf("provider: whisper local: create temp file: %w", err)
	}
	tmpPath := tmpFile.Name()
	defer os.Remove(tmpPath)

	if _, err := io.Copy(tmpFile, audio); err != nil {
		tmpFile.Close()
		return "", fmt.Errorf("provider: whisper local: write temp file: %w", err)
	}
	tmpFile.Close()

	args := []string{
		"-m", p.modelPath,
		"-f", tmpPath,
		"--no-timestamps",
		"--output-txt",
	}
	if opts.Language != "" {
		args = append(args, "-l", opts.Language)
	}

	cmd := exec.CommandContext(ctx, p.binaryPath, args...)
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("provider: whisper local: exec: %w: %s", err, stderr.String())
	}

	// whisper.cpp with --output-txt writes to <input>.txt
	txtPath := tmpPath + ".txt"
	if _, err := os.Stat(txtPath); err == nil {
		defer os.Remove(txtPath)
		data, err := os.ReadFile(filepath.Clean(txtPath))
		if err != nil {
			return "", fmt.Errorf("provider: whisper local: read output: %w", err)
		}
		text := strings.TrimSpace(string(data))
		if text == "" {
			return "", fmt.Errorf("provider: whisper local: empty transcript")
		}
		return text, nil
	}

	// fallback: some versions write to stdout
	text := strings.TrimSpace(stdout.String())
	if text == "" {
		return "", fmt.Errorf("provider: whisper local: empty transcript")
	}
	return text, nil
}

