package provider

import (
	"context"
	"encoding/json"
	"io"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"
)

func TestWhisperAPIProvider_Transcribe(t *testing.T) {
	t.Run("success", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Verify request
			if r.Method != http.MethodPost {
				t.Errorf("expected POST, got %s", r.Method)
			}
			if !strings.HasPrefix(r.Header.Get("Content-Type"), "multipart/form-data") {
				t.Errorf("expected multipart/form-data content type")
			}
			if r.Header.Get("Authorization") != "Bearer test-key" {
				t.Errorf("expected Bearer test-key, got %s", r.Header.Get("Authorization"))
			}

			// Verify multipart fields
			if err := r.ParseMultipartForm(10 << 20); err != nil {
				t.Fatalf("parse multipart: %v", err)
			}
			if r.FormValue("model") != "whisper-1" {
				t.Errorf("expected model whisper-1, got %s", r.FormValue("model"))
			}
			if r.FormValue("language") != "en" {
				t.Errorf("expected language en, got %s", r.FormValue("language"))
			}
			file, _, err := r.FormFile("file")
			if err != nil {
				t.Fatalf("expected file field: %v", err)
			}
			file.Close()

			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: "Hello, world!"})
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		text, err := p.Transcribe(context.Background(), strings.NewReader("fake audio"), TranscribeOpts{
			Language: "en",
			Format:   "wav",
		})
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if text != "Hello, world!" {
			t.Errorf("expected 'Hello, world!', got %q", text)
		}
	})

	t.Run("api error", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			http.Error(w, `{"error":"invalid api key"}`, http.StatusUnauthorized)
		}))
		defer srv.Close()

		p := NewWhisperAPI("bad-key", WithBaseURL(srv.URL))
		_, err := p.Transcribe(context.Background(), strings.NewReader("fake audio"), TranscribeOpts{})
		if err == nil {
			t.Fatal("expected error for 401 response")
		}
		if !strings.Contains(err.Error(), "status 401") {
			t.Errorf("expected status 401 in error, got: %v", err)
		}
	})

	t.Run("empty transcript", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: ""})
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		_, err := p.Transcribe(context.Background(), strings.NewReader("fake audio"), TranscribeOpts{})
		if err == nil {
			t.Fatal("expected error for empty transcript")
		}
		if !strings.Contains(err.Error(), "empty transcript") {
			t.Errorf("expected 'empty transcript' in error, got: %v", err)
		}
	})

	t.Run("invalid json", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			w.Header().Set("Content-Type", "application/json")
			_, _ = w.Write([]byte("not json"))
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		_, err := p.Transcribe(context.Background(), strings.NewReader("fake audio"), TranscribeOpts{})
		if err == nil {
			t.Fatal("expected error for invalid json")
		}
		if !strings.Contains(err.Error(), "decode response") {
			t.Errorf("expected decode error, got: %v", err)
		}
	})

	t.Run("context cancellation", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			time.Sleep(5 * time.Second)
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: "late"})
		}))
		defer srv.Close()

		ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
		defer cancel()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		_, err := p.Transcribe(ctx, strings.NewReader("fake audio"), TranscribeOpts{})
		if err == nil {
			t.Fatal("expected error for cancelled context")
		}
	})

	t.Run("no language", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			if err := r.ParseMultipartForm(10 << 20); err != nil {
				t.Fatalf("parse: %v", err)
			}
			if r.FormValue("language") != "" {
				t.Errorf("expected no language field, got %q", r.FormValue("language"))
			}
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: "auto detected"})
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		text, err := p.Transcribe(context.Background(), strings.NewReader("audio"), TranscribeOpts{})
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if text != "auto detected" {
			t.Errorf("expected 'auto detected', got %q", text)
		}
	})

	t.Run("with custom model", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			if err := r.ParseMultipartForm(10 << 20); err != nil {
				t.Fatalf("parse: %v", err)
			}
			if r.FormValue("model") != "whisper-2" {
				t.Errorf("expected model whisper-2, got %s", r.FormValue("model"))
			}
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: "v2 result"})
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL), WithModel("whisper-2"))
		text, err := p.Transcribe(context.Background(), strings.NewReader("audio"), TranscribeOpts{})
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if text != "v2 result" {
			t.Errorf("expected 'v2 result', got %q", text)
