package item

import (
	"time"

	"github.com/google/uuid"
)

// Item represents an item stored in the database.
type Item struct {
	ID           uuid.UUID
	OwnerID      uuid.UUID
	Type         string
	Status       string
	Sensitivity  string
	Title        *string
	ContentText  *string
	ContentURL   *string
	Tags         []string
	Metadata     map[string]any
	AutoMetadata map[string]any
	Source       string
	SourceURL    *string
	CreatedAt    time.Time
	UpdatedAt    time.Time
	CapturedAt   time.Time
}

// SearchResult holds a page of items with total count.
type SearchResult struct {
	Items   []*Item
	Total   int
	HasMore bool
}

// Filter describes optional filters for listing items.
type Filter struct {
	Types       []string
	Tags        []string
	Sensitivity []string
	Source      *string
	DateFrom   *time.Time
	DateTo     *time.Time
	Status     []string
}

// Sort describes ordering for item listings.
type Sort struct {
	Field     string
	Direction string
}

// BookmarkInput holds parameters for creating a bookmark item.
type BookmarkInput struct {
	URL         string
