package router

import (
	"bytes"
	"encoding/json"
	"mime/multipart"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/google/uuid"
	"github.com/ketang/flotsam/api/internal/auth"
)

func TestUploadHandler_NilStorage(t *testing.T) {
	handler := uploadHandler(nil, 50<<20)

	req := httptest.NewRequest(http.MethodPost, "/upload", nil)
	ctx := auth.WithClaims(req.Context(), &auth.Claims{UserID: uuid.New()})
	req = req.WithContext(ctx)

	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusServiceUnavailable {
		t.Errorf("expected 503, got %d", rr.Code)
	}
}

func TestUploadHandler_NoAuth(t *testing.T) {
	handler := uploadHandler(nil, 50<<20)

	req := httptest.NewRequest(http.MethodPost, "/upload", nil)
	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	// Without storage, returns 503 before checking auth
	// The auth middleware handles 401 before this handler is called,
	// but we still guard against nil claims
	if rr.Code != http.StatusServiceUnavailable {
		t.Errorf("expected 503 (nil storage checked first), got %d", rr.Code)
	}
}

func TestUploadHandler_MissingFile(t *testing.T) {
	// We can't easily test with a real storage.Client without S3,
	// so this tests the handler logic up to the storage call.
	// The handler requires a non-nil storage to proceed past the first check.
	// For unit tests, we test the MIME validation and key generation via
	// the mimeFromFilename helper and allowedAudioTypes map.
}

func TestMimeFromFilename(t *testing.T) {
	tests := []struct {
		name     string
		filename string
		want     string
	}{
		{"mp3", "audio.mp3", "audio/mpeg"},
		{"wav", "recording.wav", "audio/wav"},
		{"ogg", "file.ogg", "audio/ogg"},
		{"webm", "capture.webm", "audio/webm"},
		{"m4a", "voice.m4a", "audio/mp4"},
		{"flac", "lossless.flac", "audio/flac"},
		{"unknown", "file.txt", ""},
		{"no extension", "noext", ""},
		{"uppercase", "FILE.MP3", "audio/mpeg"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := mimeFromFilename(tt.filename)
			if got != tt.want {
				t.Errorf("mimeFromFilename(%q) = %q, want %q", tt.filename, got, tt.want)
			}
		})
	}
}

func TestAllowedAudioTypes(t *testing.T) {
	expected := map[string]string{
		"audio/mpeg":  "mp3",
		"audio/wav":   "wav",
		"audio/x-wav": "wav",
		"audio/ogg":   "ogg",
		"audio/webm":  "webm",
		"audio/mp4":   "m4a",
		"audio/x-m4a": "m4a",
		"audio/flac":  "flac",
	}

	for mime, ext := range expected {
		got, ok := allowedAudioTypes[mime]
		if !ok {
			t.Errorf("expected %q in allowedAudioTypes", mime)
			continue
		}
		if got != ext {
			t.Errorf("allowedAudioTypes[%q] = %q, want %q", mime, got, ext)
		}
	}

	// Verify non-audio types are not allowed
	disallowed := []string{"text/plain", "image/png", "video/mp4", "application/pdf"}
	for _, mime := range disallowed {
		if _, ok := allowedAudioTypes[mime]; ok {
			t.Errorf("unexpected type %q in allowedAudioTypes", mime)
		}
	}
}

func TestUploadHandler_BadContentType(t *testing.T) {
	// Create a multipart request with a non-audio file
	var buf bytes.Buffer
	w := multipart.NewWriter(&buf)
	part, err := w.CreateFormFile("file", "test.txt")
	if err != nil {
		t.Fatal(err)
	}
	_, _ = part.Write([]byte("not audio"))
	w.Close()

	// We need a non-nil storage to get past the first check.
	// Since we can't easily create a mock storage.Client (it's a struct, not an interface),
	// we test the content type validation logic indirectly through the types map.
	// The full integration test would require a running S3.
}

func TestUploadResponse_JSON(t *testing.T) {
	resp := uploadResponse{
		Key:         "user123/uploads/abc.wav",
		ContentType: "audio/wav",
		Size:        12345,
	}

	data, err := json.Marshal(resp)
	if err != nil {
		t.Fatalf("marshal: %v", err)
	}

	var decoded uploadResponse
	if err := json.Unmarshal(data, &decoded); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}

	if decoded.Key != resp.Key {
		t.Errorf("key: got %q, want %q", decoded.Key, resp.Key)
	}
	if decoded.ContentType != resp.ContentType {
		t.Errorf("content_type: got %q, want %q", decoded.ContentType, resp.ContentType)
	}
	if decoded.Size != resp.Size {
		t.Errorf("size: got %d, want %d", decoded.Size, resp.Size)
	}
}

