		}
		return text, nil
	}

	// fallback: some versions write to stdout
	text := strings.TrimSpace(stdout.String())
	if text == "" {
		return "", fmt.Errorf("provider: whisper local: empty transcript")
	}
	return text, nil
}

package router

import (
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"path/filepath"
	"strings"

	"github.com/google/uuid"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/storage"
)

// allowedAudioTypes maps MIME types to file extensions for audio uploads.
var allowedAudioTypes = map[string]string{
	"audio/mpeg":  "mp3",
	"audio/wav":   "wav",
	"audio/x-wav": "wav",
	"audio/ogg":   "ogg",
	"audio/webm":  "webm",
	"audio/mp4":   "m4a",
	"audio/x-m4a": "m4a",
	"audio/flac":  "flac",
}

type uploadResponse struct {
	Key         string `json:"key"`
	ContentType string `json:"content_type"`
	Size        int64  `json:"size"`
}

func uploadHandler(store *storage.Client, maxSize int64) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if store == nil {
			http.Error(w, "object storage not configured", http.StatusServiceUnavailable)
			return
		}

		claims := auth.GetClaims(r.Context())
		if claims == nil {
			http.Error(w, "unauthorized", http.StatusUnauthorized)
			return
		}

		// Limit request body size
		r.Body = http.MaxBytesReader(w, r.Body, maxSize)

		if err := r.ParseMultipartForm(maxSize); err != nil {
			http.Error(w, "file too large or invalid form data", http.StatusBadRequest)
			return
		}
		defer func() {
			if r.MultipartForm != nil {
				_ = r.MultipartForm.RemoveAll()
			}
		}()

		file, header, err := r.FormFile("file")
		if err != nil {
			http.Error(w, "missing file field", http.StatusBadRequest)
			return
		}
		defer file.Close()

		// Validate MIME type
		contentType := header.Header.Get("Content-Type")
		if contentType == "" {
			// Try to detect from filename
			contentType = mimeFromFilename(header.Filename)
		}
		ext, ok := allowedAudioTypes[contentType]
		if !ok {
			http.Error(w, fmt.Sprintf("unsupported audio type: %s", contentType), http.StatusBadRequest)
			return
		}

		// Generate upload key
		uploadID := uuid.New()
		key := fmt.Sprintf("%s/uploads/%s.%s", claims.UserID, uploadID, ext)

		// Upload to S3
		if err := store.Upload(r.Context(), key, file, contentType); err != nil {
			slog.ErrorContext(r.Context(), "router: upload: s3 upload failed",
				"key", key,
				"error", err,
			)
			http.Error(w, "upload failed", http.StatusInternalServerError)
			return
		}

		slog.InfoContext(r.Context(), "router: upload: completed",
			"key", key,
			"size", header.Size,
			"content_type", contentType,
		)

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(uploadResponse{
			Key:         key,
			ContentType: contentType,
			Size:        header.Size,
		})
	}
}

func mimeFromFilename(name string) string {
	ext := strings.ToLower(filepath.Ext(name))
	switch ext {
	case ".mp3":
		return "audio/mpeg"
	case ".wav":
		return "audio/wav"
	case ".ogg":
		return "audio/ogg"
	case ".webm":
		return "audio/webm"
	case ".m4a":
		return "audio/mp4"
	case ".flac":
		return "audio/flac"
	default:
		return ""
	}
}

package worker

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"path/filepath"
	"strings"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/ketang/flotsam/api/internal/storage"
)

// TranscribeArgs are the arguments for a transcription job.
type TranscribeArgs struct {
	ItemID   uuid.UUID `json:"item_id"`
	OwnerID  uuid.UUID `json:"owner_id"`
	AudioKey string    `json:"audio_key"`
}

func (TranscribeArgs) Kind() string { return "transcribe" }

// TranscribeWorker transcribes audio via Whisper API or local whisper.cpp.
type TranscribeWorker struct {
	river.WorkerDefaults[TranscribeArgs]
	Storage     *storage.Client
	Transcriber provider.Transcriber
	Pool        *pgxpool.Pool
}

func (w *TranscribeWorker) Work(ctx context.Context, job *river.Job[TranscribeArgs]) error {
	slog.InfoContext(ctx, "worker: transcribe: processing",
		"item_id", job.Args.ItemID,
		"audio_key", job.Args.AudioKey,
	)

	if w.Storage == nil {
		return fmt.Errorf("worker: transcribe: storage not configured")
	}
	if w.Transcriber == nil {
		return fmt.Errorf("worker: transcribe: transcriber not configured")
	}

	// Update item status to processing
	if err := w.updateStatus(ctx, job.Args.ItemID, job.Args.OwnerID, "processing", nil); err != nil {
		return fmt.Errorf("worker: transcribe: set processing: %w", err)
	}

	// Download audio from S3
	reader, err := w.Storage.Download(ctx, job.Args.AudioKey)
	if err != nil {
		w.setError(ctx, job.Args.ItemID, job.Args.OwnerID, "failed to download audio")
		return fmt.Errorf("worker: transcribe: download audio: %w", err)
	}
	defer reader.Close()

	// Determine format from key extension
	ext := strings.TrimPrefix(filepath.Ext(job.Args.AudioKey), ".")
	if ext == "" {
		ext = "wav"
	}

	// Transcribe
	transcript, err := w.Transcriber.Transcribe(ctx, reader, provider.TranscribeOpts{
		Format: ext,
	})
	if err != nil {
		w.setError(ctx, job.Args.ItemID, job.Args.OwnerID, "transcription failed")
		return fmt.Errorf("worker: transcribe: transcribe: %w", err)
	}

	// Update item with transcript
	_, err = w.Pool.Exec(ctx,
		`UPDATE items SET content_text = $1, status = 'ready', updated_at = now()
		 WHERE id = $2 AND owner_id = $3`,
		transcript, job.Args.ItemID, job.Args.OwnerID)
	if err != nil {
		return fmt.Errorf("worker: transcribe: update item: %w", err)
	}

	slog.InfoContext(ctx, "worker: transcribe: completed",
		"item_id", job.Args.ItemID,
		"transcript_len", len(transcript),
	)
	return nil
}

// updateStatus sets the item's status and optionally stores an error in metadata.
func (w *TranscribeWorker) updateStatus(ctx context.Context, itemID, ownerID uuid.UUID, status string, errMsg *string) error {
	if errMsg != nil {
		meta := map[string]any{"error": *errMsg}
		metaJSON, err := json.Marshal(meta)
		if err != nil {
			return fmt.Errorf("worker: transcribe: marshal error metadata: %w", err)
		}
		_, err = w.Pool.Exec(ctx,
			`UPDATE items SET status = $1, metadata = metadata || $4::jsonb, updated_at = now()
			 WHERE id = $2 AND owner_id = $3`,
			status, itemID, ownerID, metaJSON)
		return err
	}
	_, err := w.Pool.Exec(ctx,
		`UPDATE items SET status = $1, updated_at = now() WHERE id = $2 AND owner_id = $3`,
		status, itemID, ownerID)
	return err
}

// setError is a convenience method that sets the item status to "error".
func (w *TranscribeWorker) setError(ctx context.Context, itemID, ownerID uuid.UUID, msg string) {
	if err := w.updateStatus(ctx, itemID, ownerID, "error", &msg); err != nil {
		slog.ErrorContext(ctx, "worker: transcribe: failed to set error status",
			"item_id", itemID,
			"error", err,
		)
	}
}

package provider

import (
	"context"
	"encoding/json"
	"io"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"
)

func TestWhisperAPIProvider_Transcribe(t *testing.T) {
	t.Run("success", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Verify request
			if r.Method != http.MethodPost {
				t.Errorf("expected POST, got %s", r.Method)
			}
			if !strings.HasPrefix(r.Header.Get("Content-Type"), "multipart/form-data") {
				t.Errorf("expected multipart/form-data content type")
			}
			if r.Header.Get("Authorization") != "Bearer test-key" {
				t.Errorf("expected Bearer test-key, got %s", r.Header.Get("Authorization"))
			}

			// Verify multipart fields
			if err := r.ParseMultipartForm(10 << 20); err != nil {
				t.Fatalf("parse multipart: %v", err)
			}
			if r.FormValue("model") != "whisper-1" {
				t.Errorf("expected model whisper-1, got %s", r.FormValue("model"))
			}
			if r.FormValue("language") != "en" {
				t.Errorf("expected language en, got %s", r.FormValue("language"))
			}
			file, _, err := r.FormFile("file")
			if err != nil {
				t.Fatalf("expected file field: %v", err)
			}
			file.Close()

			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: "Hello, world!"})
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		text, err := p.Transcribe(context.Background(), strings.NewReader("fake audio"), TranscribeOpts{
			Language: "en",
			Format:   "wav",
		})
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if text != "Hello, world!" {
			t.Errorf("expected 'Hello, world!', got %q", text)
		}
	})

	t.Run("api error", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			http.Error(w, `{"error":"invalid api key"}`, http.StatusUnauthorized)
		}))
		defer srv.Close()

		p := NewWhisperAPI("bad-key", WithBaseURL(srv.URL))
		_, err := p.Transcribe(context.Background(), strings.NewReader("fake audio"), TranscribeOpts{})
		if err == nil {
			t.Fatal("expected error for 401 response")
		}
		if !strings.Contains(err.Error(), "status 401") {
			t.Errorf("expected status 401 in error, got: %v", err)
		}
	})

	t.Run("empty transcript", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: ""})
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		_, err := p.Transcribe(context.Background(), strings.NewReader("fake audio"), TranscribeOpts{})
		if err == nil {
			t.Fatal("expected error for empty transcript")
		}
		if !strings.Contains(err.Error(), "empty transcript") {
			t.Errorf("expected 'empty transcript' in error, got: %v", err)
		}
	})

	t.Run("invalid json", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			w.Header().Set("Content-Type", "application/json")
			_, _ = w.Write([]byte("not json"))
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		_, err := p.Transcribe(context.Background(), strings.NewReader("fake audio"), TranscribeOpts{})
		if err == nil {
			t.Fatal("expected error for invalid json")
		}
		if !strings.Contains(err.Error(), "decode response") {
			t.Errorf("expected decode error, got: %v", err)
		}
	})

	t.Run("context cancellation", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			time.Sleep(5 * time.Second)
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: "late"})
		}))
		defer srv.Close()

		ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
		defer cancel()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		_, err := p.Transcribe(ctx, strings.NewReader("fake audio"), TranscribeOpts{})
		if err == nil {
			t.Fatal("expected error for cancelled context")
		}
	})

	t.Run("no language", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			if err := r.ParseMultipartForm(10 << 20); err != nil {
				t.Fatalf("parse: %v", err)
			}
			if r.FormValue("language") != "" {
				t.Errorf("expected no language field, got %q", r.FormValue("language"))
			}
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: "auto detected"})
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		text, err := p.Transcribe(context.Background(), strings.NewReader("audio"), TranscribeOpts{})
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if text != "auto detected" {
			t.Errorf("expected 'auto detected', got %q", text)
		}
	})

	t.Run("with custom model", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			if err := r.ParseMultipartForm(10 << 20); err != nil {
				t.Fatalf("parse: %v", err)
			}
			if r.FormValue("model") != "whisper-2" {
				t.Errorf("expected model whisper-2, got %s", r.FormValue("model"))
			}
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(whisperResponse{Text: "v2 result"})
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL), WithModel("whisper-2"))
		text, err := p.Transcribe(context.Background(), strings.NewReader("audio"), TranscribeOpts{})
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if text != "v2 result" {
			t.Errorf("expected 'v2 result', got %q", text)
		}
	})

	t.Run("server error body", func(t *testing.T) {
		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			w.WriteHeader(http.StatusInternalServerError)
			_, _ = io.WriteString(w, "internal server error")
		}))
		defer srv.Close()

		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
		_, err := p.Transcribe(context.Background(), strings.NewReader("audio"), TranscribeOpts{})
		if err == nil {
			t.Fatal("expected error for 500 response")
		}
		if !strings.Contains(err.Error(), "status 500") {
			t.Errorf("expected status 500 in error, got: %v", err)
		}
	})
}

func TestNewWhisperAPI_Defaults(t *testing.T) {
	p := NewWhisperAPI("key123")
	if p.apiKey != "key123" {
		t.Errorf("expected apiKey key123, got %s", p.apiKey)
	}
	if p.model != defaultWhisperModel {
		t.Errorf("expected model %s, got %s", defaultWhisperModel, p.model)
	}
	if p.baseURL != defaultWhisperBaseURL {
		t.Errorf("expected baseURL %s, got %s", defaultWhisperBaseURL, p.baseURL)
	}
}

func TestNewWhisperLocal(t *testing.T) {
	p := NewWhisperLocal("/usr/bin/whisper", "/models/ggml-base.bin")
	if p.binaryPath != "/usr/bin/whisper" {
		t.Errorf("expected binaryPath /usr/bin/whisper, got %s", p.binaryPath)
	}
	if p.modelPath != "/models/ggml-base.bin" {
		t.Errorf("expected modelPath /models/ggml-base.bin, got %s", p.modelPath)
	}
}

package router

import (
	"bytes"
	"encoding/json"
	"mime/multipart"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/google/uuid"
	"github.com/ketang/flotsam/api/internal/auth"
)

func TestUploadHandler_NilStorage(t *testing.T) {
	handler := uploadHandler(nil, 50<<20)

	req := httptest.NewRequest(http.MethodPost, "/upload", nil)
	ctx := auth.WithClaims(req.Context(), &auth.Claims{UserID: uuid.New()})
	req = req.WithContext(ctx)

	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusServiceUnavailable {
		t.Errorf("expected 503, got %d", rr.Code)
	}
}

func TestUploadHandler_NoAuth(t *testing.T) {
	handler := uploadHandler(nil, 50<<20)

	req := httptest.NewRequest(http.MethodPost, "/upload", nil)
	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	// Without storage, returns 503 before checking auth
	// The auth middleware handles 401 before this handler is called,
	// but we still guard against nil claims
	if rr.Code != http.StatusServiceUnavailable {
		t.Errorf("expected 503 (nil storage checked first), got %d", rr.Code)
	}
}

func TestUploadHandler_MissingFile(t *testing.T) {
	// We can't easily test with a real storage.Client without S3,
	// so this tests the handler logic up to the storage call.
	// The handler requires a non-nil storage to proceed past the first check.
	// For unit tests, we test the MIME validation and key generation via
	// the mimeFromFilename helper and allowedAudioTypes map.
}

func TestMimeFromFilename(t *testing.T) {
	tests := []struct {
		name     string
		filename string
		want     string
	}{
		{"mp3", "audio.mp3", "audio/mpeg"},
		{"wav", "recording.wav", "audio/wav"},
		{"ogg", "file.ogg", "audio/ogg"},
		{"webm", "capture.webm", "audio/webm"},
		{"m4a", "voice.m4a", "audio/mp4"},
		{"flac", "lossless.flac", "audio/flac"},
		{"unknown", "file.txt", ""},
		{"no extension", "noext", ""},
		{"uppercase", "FILE.MP3", "audio/mpeg"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := mimeFromFilename(tt.filename)
			if got != tt.want {
				t.Errorf("mimeFromFilename(%q) = %q, want %q", tt.filename, got, tt.want)
			}
		})
	}
}

func TestAllowedAudioTypes(t *testing.T) {
	expected := map[string]string{
		"audio/mpeg":  "mp3",
		"audio/wav":   "wav",
		"audio/x-wav": "wav",
		"audio/ogg":   "ogg",
		"audio/webm":  "webm",
		"audio/mp4":   "m4a",
		"audio/x-m4a": "m4a",
		"audio/flac":  "flac",
	}

	for mime, ext := range expected {
		got, ok := allowedAudioTypes[mime]
		if !ok {
			t.Errorf("expected %q in allowedAudioTypes", mime)
			continue
		}
		if got != ext {
			t.Errorf("allowedAudioTypes[%q] = %q, want %q", mime, got, ext)
		}
	}

	// Verify non-audio types are not allowed
	disallowed := []string{"text/plain", "image/png", "video/mp4", "application/pdf"}
	for _, mime := range disallowed {
		if _, ok := allowedAudioTypes[mime]; ok {
			t.Errorf("unexpected type %q in allowedAudioTypes", mime)
		}
	}
}

func TestUploadHandler_BadContentType(t *testing.T) {
	// Create a multipart request with a non-audio file
	var buf bytes.Buffer
	w := multipart.NewWriter(&buf)
	part, err := w.CreateFormFile("file", "test.txt")
	if err != nil {
		t.Fatal(err)
	}
	_, _ = part.Write([]byte("not audio"))
	w.Close()

	// We need a non-nil storage to get past the first check.
	// Since we can't easily create a mock storage.Client (it's a struct, not an interface),
	// we test the content type validation logic indirectly through the types map.
	// The full integration test would require a running S3.
}

func TestUploadResponse_JSON(t *testing.T) {
	resp := uploadResponse{
		Key:         "user123/uploads/abc.wav",
		ContentType: "audio/wav",
		Size:        12345,
	}

	data, err := json.Marshal(resp)
	if err != nil {
		t.Fatalf("marshal: %v", err)
	}

	var decoded uploadResponse
	if err := json.Unmarshal(data, &decoded); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}

	if decoded.Key != resp.Key {
		t.Errorf("key: got %q, want %q", decoded.Key, resp.Key)
	}
	if decoded.ContentType != resp.ContentType {
		t.Errorf("content_type: got %q, want %q", decoded.ContentType, resp.ContentType)
	}
	if decoded.Size != resp.Size {
		t.Errorf("size: got %d, want %d", decoded.Size, resp.Size)
	}
}
